#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int freq[101] = {0};
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x >= 1 && x <= 100) freq[x]++;
        }
        int fraud = 0;
        for (int i = 1; i <= 100; ++i) {
            if (freq[i] > 1) fraud += freq[i] - 1;
        }
        printf("%d\n", fraud);
    }
    return 0;
}

