#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = [0] * 101
        for _ in range(N):
            x = int(next(it))
            if 1 <= x <= 100:
                freq[x] += 1
        fraud = sum(c - 1 for c in freq if c > 1)
        out_lines.append(str(fraud))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

